<?phpnamespace Nemundo\App\Scheduler\Setup;use Nemundo\App\Application\Setup\AbstractSetup;use Nemundo\App\Application\Type\AbstractApplication;use Nemundo\App\Scheduler\Data\Scheduler\Scheduler;use Nemundo\App\Scheduler\Data\Scheduler\SchedulerCount;use Nemundo\App\Scheduler\Data\Scheduler\SchedulerDelete;use Nemundo\App\Scheduler\Data\Scheduler\SchedulerUpdate;use Nemundo\App\Scheduler\Data\SchedulerLog\SchedulerLogDelete;use Nemundo\App\Scheduler\Job\AbstractScheduler;class SchedulerSetup extends AbstractSetup{    public function addScheduler(AbstractScheduler $scheduler)    {        $count = new SchedulerCount();        $count->filter->andEqual($count->model->phpClass, $scheduler->getClassName());        if ($count->getCount() === 0) {            $data = new Scheduler();            $data->active = false;            $data->running = false;            $data->phpClass = $scheduler->getClassName();            if ($this->application !== null) {                $data->applicationId = $this->application->applicationId;            }            $data->setupStatus = true;            $data->save();        } else {            $update = new SchedulerUpdate();            $update->setupStatus = true;            $update->filter->andEqual($update->model->phpClass, $scheduler->getClassName());            $update->update();        }        return $this;    }    public function removeScheduler(AbstractScheduler $scheduler)    {        /*$id = new ScriptId();        $id->filter->andEqual($id->model->scriptClass, $scheduler->getClassName());        $scriptId = $id->getId();        $id = new SchedulerId();        $id->filter->andEqual($id->model->scriptId, $scriptId);        $schedulerId = $id->getId();*/        $schedulerId = $scheduler->getSchedulerId();        $delete = new SchedulerLogDelete();        $delete->filter->andEqual($delete->model->schedulerId, $schedulerId);        $delete->delete();        $delete = new SchedulerDelete();        $delete->filter->andEqual($delete->model->id, $scheduler->getSchedulerId());        $delete->delete();        //(new ScriptSetup())->removeScript($scheduler);    }    public function removeSchedulerByApplication(AbstractApplication $application)    {        /*$reader = new SchedulerReader();        $reader->model->loadScript();        $reader->filter->andEqual($reader->model->script->applicationId, $application->applicationId);        foreach ($reader->getData() as $schedulerRow) {            $delete = new SchedulerLogDelete();            $delete->filter->andEqual($delete->model->schedulerId, $schedulerRow->id);            $delete->delete();            (new SchedulerDelete())->deleteById($schedulerRow->id);            (new ScriptDelete())->deleteById($schedulerRow->scriptId);        }*/    }}